        //DimensionFocusBalance
        ttsbegin;

        select * from ledger where ledger.Description == "Falcon Gas Zambia Limited";
        {
            while  select forupdate  DimensionFocusBalance where DimensionFocusBalance.Ledger == ledger.recid
